import pytest
from hypothesis import given, strategies as st, settings, HealthCheck
from hypothesis.stateful import RuleBasedStateMachine, rule, invariant


# ─── REQ-001 cross-module atomicity invariant ──────────────────────────────


@given(
    surface_outcomes=st.lists(
        st.fixed_dictionaries(
            {
                "push": st.booleans(),
                "in_app": st.booleans(),
                "sound": st.booleans(),
                "badge": st.booleans(),
            }
        ),
        min_size=1,
        max_size=20,
    )
)
@settings(max_examples=500, deadline=None, suppress_health_check=[HealthCheck.function_scoped_fixture])
def test_mention_dispatch_atomicity_across_surfaces_and_counters_invariant(
    surface_outcomes, db, http_client, seeded_channel, member_with_dnd
):
    """Property: invariant (REQ-001). Across any sequence of dispatch attempts
    with arbitrary per-surface success/failure, the invariant `delivered ==
    (any surface succeeded)` holds, AND the badge counter equals the count of
    deliveries where badge surface succeeded. Atomicity boundary: the API
    success report MUST NOT diverge from the DB counter state."""
    member_with_dnd("U2")
    delivered_count = 0
    badge_success_count = 0
    for outcome in surface_outcomes:
        resp = http_client.post(
            "/api/messages",
            json={
                "author": "U1",
                "channel": seeded_channel,
                "text": "@U2 ping",
                "mention_ids": ["U2"],
                "_force_surface_outcomes": outcome,  # test hook
            },
        )
        body = resp.json()
        any_succeeded = any(outcome.values())
        assert body["delivered"] is any_succeeded
        if any_succeeded:
            delivered_count += 1
        if outcome["badge"]:
            badge_success_count += 1
    row = db.execute(
        "SELECT unread_badge_count FROM member_counters WHERE member_id = %s",
        ["U2"],
    ).fetchone()
    actual_badge = row[0] if row else 0
    assert actual_badge == badge_success_count


# ─── REQ-002 mute-channel persistence across restart ───────────────────────


class _MutedChannelPersistenceMachine(RuleBasedStateMachine):
    """Property: invariant (REQ-002 glossary clause iii).
    Mute/unmute operations on a channel are persisted such that after an
    app restart (simulated via re-creating the app fixture from the same
    Postgres URL), the mute state — and the silence behavior it implies —
    is preserved exactly."""

    def __init__(self):
        super().__init__()
        from src.app import make_app
        self._make_app = make_app
        self.db_uri = pytest._integration_db_uri  # injected below
        self.redis_uri = pytest._integration_redis_uri
        self.app = make_app(db_uri=self.db_uri, redis_uri=self.redis_uri)
        from starlette.testclient import TestClient
        self.client = TestClient(self.app)
        # Bootstrap: seed channel + member.
        self.client.post("/api/_test/seed", json={
            "channel": "C1", "members": ["U1", "U2"]
        })
        self.muted = False

    @rule()
    def mute_channel(self):
        self.client.put("/api/members/U2/dnd", json={"muted_channels": ["C1"]})
        self.muted = True

    @rule()
    def unmute_channel(self):
        self.client.put("/api/members/U2/dnd", json={"muted_channels": []})
        self.muted = False

    @rule()
    def restart_app(self):
        from starlette.testclient import TestClient
        # Build a fresh app instance against the same DB. Tests that mute
        # state persists across the restart.
        self.app = self._make_app(db_uri=self.db_uri, redis_uri=self.redis_uri)
        self.client = TestClient(self.app)

    @invariant()
    def mute_state_silences_consistently(self):
        # Send a mention; check whether push fires in line with the mute state.
        resp = self.client.post(
            "/api/messages",
            json={"author": "U1", "channel": "C1", "text": "@U2", "mention_ids": ["U2"]},
        )
        body = resp.json()
        if self.muted:
            assert "PushSurface" not in body["surfaces_fired"]
        else:
            assert "PushSurface" in body["surfaces_fired"]


def test_per_channel_mute_consistently_silences_across_restart_invariant(
    postgres_url, redis_url
):
    """Property: invariant (REQ-002 glossary iii). Mute state survives an
    app restart — silence behavior consistent across the restart boundary."""
    pytest._integration_db_uri = postgres_url  # noqa — passed in via fixture
    pytest._integration_redis_uri = redis_url
    _MutedChannelPersistenceMachine.TestCase.settings = settings(
        max_examples=500,
        deadline=None,
        suppress_health_check=[HealthCheck.function_scoped_fixture],
    )
    t = _MutedChannelPersistenceMachine.TestCase("runTest")
    t.runTest()
